<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('hosting.view');$pageTitle='Hosting Accounts';require VP3_ROOT.'/includes/admin-header.php';$cid=(int)vp3_input('customer_id');$sql='SELECT h.*,c.name customer_name,p.name product_name,l.license_key_prefix FROM hosting_accounts h JOIN customers c ON c.id=h.customer_id JOIN products p ON p.id=h.product_id LEFT JOIN licenses l ON l.id=h.license_id';$params=[];if($cid){$sql.=' WHERE h.customer_id=?';$params[]=$cid;}$sql.=' ORDER BY h.id DESC LIMIT 250';$s=vp3_db()->prepare($sql);$s->execute($params);$rows=$s->fetchAll();?><div class="hero-actions"><h1>Hosting accounts</h1><a class="button small" href="hosting-account.php">New hosting account</a></div><div class="table-wrap"><table class="table"><thead><tr><th>Customer</th><th>Hostname</th><th>Product</th><th>Hosting</th><th>Install</th><th>Version</th><th></th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['customer_name'])?></td><td><?=vp3_e($x['subdomain'].'.'.vp3_config('hosting.base_domain'))?></td><td><?=vp3_e($x['product_name'])?></td><td><span class="badge <?=vp3_e($x['hosting_status'])?>"><?=vp3_e($x['hosting_status'])?></span></td><td><span class="badge <?=vp3_e($x['installation_status'])?>"><?=vp3_e($x['installation_status'])?></span></td><td><?=vp3_e($x['installed_version'])?></td><td><a href="hosting-account.php?id=<?=(int)$x['id']?>">Open</a></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>